#!/usr/bin/env python3
"""Fix all translated page titles and meta descriptions."""
import re
from pathlib import Path

BASE = Path("/tmp/exknowledge")

def update_file(filepath, new_title, new_desc):
    content = filepath.read_text(encoding='utf-8')
    content = re.sub(r'<title>[^<]*</title>', f'<title>{new_title}</title>', content, count=1)
    content = re.sub(r'<meta name="description" content="[^"]*">', f'<meta name="description" content="{new_desc}">', content, count=1)
    content = re.sub(r'<meta property="og:description" content="[^"]*">', f'<meta property="og:description" content="{new_desc}">', content, count=1)
    filepath.write_text(content, encoding='utf-8')

