count = 0
for lang, pages in DATA.items():
    for page, (title, desc) in pages.items():
        if page == "index":
            fp = BASE / lang / "index.html"
        else:
            fp = BASE / lang / "pages" / f"{page}.html"
        if fp.exists():
            update_file(fp, title, desc)
            count += 1
        else:
            print(f"MISSING: {fp}")

print(f"Updated {count} files with new titles and descriptions")
